var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Mm…","TWN":"嗯…"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"침대에서 깨어나는 게 아주 일상이네.","JPN":"いつの間にか気を失い、気づいたらベッドの上……もう日常になってしまったな。","ENG":"Waking up in a bed again. Seems like a habit.","TWN":"在床上醒來已經是家常便飯呢。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내 다리에 감각이 없어.","JPN":"足に感覚がない。","ENG":"I can't feel my legs.","TWN":"腳沒有知覺。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"나무에 빨래처럼 걸려서 기절해있었으니까.","JPN":"気絶している間、木の枝に洗濯物のように引っかかっていたからな。","ENG":"You were hanging from a tree like laundry while you passed out.","TWN":"因為你暈倒的時候，像洗好的衣服一樣掛在樹上。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"우리가 도시로 간 사이, 예정 주기에 없던 먹비가 쏟아졌더군.","JPN":"私たちが都市に出ている間、予定周期にはなかった墨雨が降ったようだ。","ENG":"While we were in the city, an unscheduled wave of Ink Rain hit.","TWN":"我們去城市的這段時間，下了一場不在預期週期裡的墨雨。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"침식현상의 주기는 절대적이지 않으니까. 어디까지나 참고용일 뿐이지.","JPN":"侵食現象の周期は絶対的ではない。あくまで参考にしているだけだ。","ENG":"The Counterside Effect cycle isn't absolute. It's only a reference point.","TWN":"侵蝕現象的週期不是絕對的，只是參考值而已。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"앤디 말로는 장치가 가동된 흔적이 있다고 했어.","JPN":"アンディーの話によると、装置が稼働した痕跡があったそうだが。","ENG":"Andy said she found signs that the device had been activated.","TWN":"安狄說裝置有運作過的痕跡。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"얼마나 위험한 지도 모르면서 혼자 뛰어든 거야?","JPN":"どれほど危険かも知らないくせに、一人で飛び込んだのか？","ENG":"Did you jump in without knowing how dangerous it was?","TWN":"你連那有多危險都不知道，就一個人衝進去了嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"<color=#ffd34c>과.위.힘</color>은 비축할 방도가 없는 휘발성 에너지니까.","JPN":"<color=#ffd34c>過向力</color>は備蓄する術がない、揮発性のエネルギーゆえ。","ENG":"<color=#ffd34c>PTP</color> is a volatile energy. There's no way to store it.","TWN":"<color=#ffd34c>回力量</color>是一種沒有儲存方法的揮發性能量。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이번 기회를 놓치면 언제 또 작동할지 모르잖나.","JPN":"この機会を逃せば、次はいつ稼働できるか分からないではないか。","ENG":"If I missed this opportunity, I wouldn't know when it might run again.","TWN":"要是錯過這次機會，不知道什麼時候才會再運作。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"과거는 다녀왔나? 이번엔 거기서 뭘 보고 누굴 만났지?","JPN":"それで、過去には行ってきたのか？　今回はそこで何を見、誰に会った？","ENG":"So? Did you go back to the past? What did you see, and who did you meet this time?","TWN":"你回到過去了嗎？這次在那裡看到什麼？見到了誰？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"다 설명하려면 얘기가 좀 길어질 텐데. 괜찮겠나?","JPN":"すべて説明すると長くなるが、よいのか？","ENG":"It'll be a long story if I explain everything. Is that all right?","TWN":"說來話長，你有時間嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"걱정 마. 땅콩이라면 잔뜩 사왔으니까.","JPN":"心配するな。ピーナッツなら山ほど買ってある。","ENG":"Go ahead. I brought plenty of peanuts.","TWN":"放心，我買了很多花生。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부는 그 연화 언니를 다시 만난 거구나.","JPN":"じゃあ、そのレンカってお姉さんにまた会えたんだね。","ENG":"So you saw that Yeonhwa lady again, huh?","TWN":"你又見到那個蓮華姊姊啦。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼 이번에도 그 언니한테 당하고 돌아온 거야?","JPN":"それで、今回もそのお姉さんにやられて帰らされたの？","ENG":"Did she beat you up again this time?","TWN":"所以這次也是被那個姊姊打敗後回到現實嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"적어도 이번엔 기습이 아닌 정당한 대결이었지.","JPN":"少なくとも今回は不意打ちではない正面からの勝負であった。","ENG":"At least this time it was a duel, not an ambush.","TWN":"至少這次不是偷襲，是正面對決。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"너를 돕겠다고 하니, 내 실력을 증명하라며 칼을 뽑더군.","JPN":"彼女を助けると言うと、某の腕を証明してみろと剣を抜いてきてな。","ENG":"I told her I came to help, and she drew her sword to see if I had what it takes.","TWN":"我說要幫助她，她就拔出劍，要我證明我的實力。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래서 졌나?","JPN":"それで負けたのか？","ENG":"So you lost?","TWN":"然後你打輸了？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나름대로 준비된 줄 알았지만, 얼마 버티지 못했네.","JPN":"自分なりに十分鍛えていると思っていたが、そう長くは持たなかった。","ENG":"I thought I trained enough, but I couldn't hold out for long.","TWN":"我以為我已經受過很多訓練，但還是一下就敗陣。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그리고 보다시피, 이렇게 강제로 돌아오게 됐지.","JPN":"そして見ての通り、帰って来たというわけだ。","ENG":"And as you can see, here I am again.","TWN":"接著就像你們看到的一樣，我回到這裡。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 언니도 좀 이해가 안 되네. 도와주러 왔다는 사람을 그런 식으로 밀어내다니.","JPN":"そのお姉さんも変わってるね。助けに来たって人をそんな風に拒むだなんて。","ENG":"I don't get her. Why push away someone who came to help?","TWN":"那個姊姊也真奇怪，為何要推開一個想要來幫忙的人？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부의 동료라면서, 왜 계속 그러는 걸까?","JPN":"師匠の仲間なのに、毎回なんでだろう？","ENG":"She's your old comrade, isn't she? Why is she still like that?","TWN":"她不是師父的夥伴嗎？為什麼要推開夥伴？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"실전에서 어설픈 도움은 발목만 잡을 뿐이란 거겠지.","JPN":"実践では下手な助太刀など、足手まといにしかならんということだろう。","ENG":"Maybe because sloppy help in the field can be more of a hindrance.","TWN":"大概是覺得在實戰中，三腳貓的功夫只會幫倒忙吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"서생을 압도할 정도의 실력자도 살아남지 못할 작전이라면, 충분히 합리적인 판단이야.","JPN":"ショウを圧倒するほどの実力者が生き残れなかったわけだし、合理的な判断だな。","ENG":"If someone strong enough to overwhelm Seosaeng still didn't survive, then her judgment isn't wrong.","TWN":"要是她的能力好到可以打倒書生，但卻連她都沒能活下來，那她的判斷完全是合理的。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"부정은 못하겠군. 내가 그녀보다 강했다면 결과는 달랐을 테니.","JPN":"否定できんな。某が彼女より強かったなら、結果は違ったであろう。","ENG":"I won't argue. If I were stronger than her, it might have turned out differently.","TWN":"我無法反駁。如果我比她強，結果肯定會不同。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신에게 그 연화라는 사람은 과거로 가서 도와야 할 만큼 중요한 사람인가?","JPN":"お前にとってそのレンカって人は、過去に戻って助けないといけないほど大事な人間なのか？","ENG":"Is she really someone you'd go back in time to save?","TWN":"對你來說，那個叫蓮華的人是重要到必須回到過去去幫助她的人嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};